{
  "sql": "SELECT g.Name AS Genre, SUM(il.UnitPrice * il.Quantity) AS TotalSales FROM Genre g JOIN Track t ON g.GenreId = t.GenreId JOIN InvoiceLine il ON t.TrackId = il.TrackId GROUP BY g.Name ORDER BY TotalSales DESC LIMIT 5",
  "rationale": "Join Genre to Track to InvoiceLine, sum UnitPrice * Quantity per genre, order descending, and limit to 5."
}

{
  "sql": "SELECT Album.Title FROM Album JOIN Artist ON Album.ArtistId = Artist.ArtistId WHERE Artist.Name = 'AC/DC'",
  "rationale": "Join Album and Artist tables to filter by artist name and return album titles."
}

{
  "sql": "SELECT mt.Name FROM MediaType mt JOIN Track t ON mt.MediaTypeId = t.MediaTypeId GROUP BY mt.MediaTypeId ORDER BY COUNT(*) DESC LIMIT 1",
  "rationale": "Count tracks per media type and return the one with the highest count."
}

{
  "sql": "SELECT e.FirstName || ' ' || e.LastName AS EmployeeName FROM Customer c JOIN Employee e ON c.SupportRepId = e.EmployeeId WHERE c.SupportRepId IS NOT NULL GROUP BY e.EmployeeId ORDER BY COUNT(*) DESC LIMIT 1",
  "rationale": "Count customers per support rep, order by count descending, and limit to one to get the employee with the most assigned customers."
}

{
  "sql": "SELECT SUM(il.UnitPrice * il.Quantity) AS total_revenue FROM Invoice i JOIN InvoiceLine il ON i.InvoiceId = il.InvoiceId WHERE strftime('%Y', i.InvoiceDate) = '2021'",
  "rationale": "Revenue is computed as the sum of UnitPrice * Quantity from InvoiceLine for invoices with an InvoiceDate in the year 2021."
}

{
  "sql": "SELECT BillingCountry, AVG(Total) AS AverageTotal FROM Invoice GROUP BY BillingCountry ORDER BY AverageTotal DESC",
  "rationale": "Group invoices by billing country and compute the average total, then order from highest to lowest."
}

{
"sql": "SELECT Genre.Name AS Genre, SUM(InvoiceLine.UnitPrice * InvoiceLine.Quantity) AS TotalSales FROM Genre JOIN Track ON Track.GenreId = Genre.GenreId JOIN InvoiceLine ON InvoiceLine.TrackId = Track.TrackId GROUP BY Genre.Name ORDER BY TotalSales DESC LIMIT 5",
"rationale": "Joins Genre, Track, and InvoiceLine to compute total sales (SUM of UnitPrice * Quantity) per genre, then returns the top 5 by descending total sales."
}

{
"sql": "SELECT FirstName || ' ' || LastName AS Name FROM Employee JOIN Customer ON Employee.EmployeeId = Customer.SupportRepId GROUP BY Employee.EmployeeId ORDER BY COUNT(CustomerId) DESC LIMIT 1",
"rationale": "Join Employee and Customer on SupportRepId, group by employee, count customers per employee, and return the top one ordered descending."
}

{
"sql": "SELECT Playlist.Name, COUNT(PlaylistTrack.TrackId) AS TrackCount FROM Playlist LEFT JOIN PlaylistTrack ON Playlist.PlaylistId = PlaylistTrack.PlaylistId GROUP BY Playlist.PlaylistId, Playlist.Name",
"rationale": "Counts the number of tracks per playlist by joining Playlist with the linking table PlaylistTrack and grouping by playlist."
}

{
"sql": "SELECT SUM(Total) AS TotalRevenue FROM Invoice WHERE strftime('%Y', InvoiceDate) = '2021'",
"rationale": "Sum the Total column from Invoice table filtered to records where the year of InvoiceDate is 2021."
}
